import{Handle}from"./Handle.js";class Template extends Handle{constructor(){super(),this.hidden=!0,this.count=0}onblamready(){this.setToFrom(),this.init()}init(){this.template=this.innerHTML,this.innerHTML=""}interpolate(template,data){let interpolated=template.replace(/\[\[(.*?)\]\]/g,(match,prop)=>data[prop]);this.additive?(this.count>=this.max&&(this.toElems[0].innerHTML="",this.count=0),this.toElems[0].innerHTML+=interpolated):this.toElems[0].innerHTML=interpolated,this.additive&&this.count++}get additive(){return this.hasAttribute("additive")}set additive(value){this.toBoolean("additive",value)}get max(){return this.getAttribute("max")||16}set max(value){this.setAttribute("max",value)}}export{Template};